function formatarHora(hora) {
  if (!hora) return '00:00:00';
  if (/^\d{2}:\d{2}:\d{2}$/.test(hora)) return hora;
  if (/^\d{2}:\d{2}$/.test(hora)) return `${hora}:00`;
